    },
    {
      "step_order": 2,
      "action_type": "Zoom",
      "direction": "In",
      "guide_text": "拉近镜头，将左侧两位人物充满画面，裁剪掉右侧的伞和人物，使画面更简洁，主题更明确。"
    }
  ]
}
